const input = items[0].json;
const obj = Array.isArray(input) ? input[0] : input;

if (!obj || typeof obj.output !== 'string') {
  throw new Error('Invalid input format');
}

const raw = obj.output;

// Extract JSON block
const first = raw.indexOf('{');
const last = raw.lastIndexOf('}');

if (first === -1 || last === -1) {
  throw new Error('No JSON found');
}

let jsonString = raw.slice(first, last + 1);

// escape raw newlines inside string values (crucial for your case)
jsonString = jsonString.replace(
  /"reply_markdown"\s*:\s*"([\s\S]*?)"/,
  (match, p1) => {
    const fixed = p1
      .replace(/\n/g, '\\n')
      .replace(/\r/g, '\\r')
      .replace(/"/g, '\\"');

    return `"reply_markdown":"${fixed}"`;
  }
);

let parsed;

try {
  parsed = JSON.parse(jsonString);
} catch (e) {
  throw new Error(
    'JSON parse failed AFTER repair: ' + e.message + '\n--- RAW ---\n' + jsonString
  );
}

return [{ json: parsed }];

