const body = $input.first().json.body;

if (!body || !body.payload) {
  throw new Error('Missing Slack payload');
}

let payload;
try {
  payload = typeof body.payload === 'string' ? JSON.parse(body.payload) : body.payload;
} catch (e) {
  throw new Error('Failed to parse Slack payload: ' + e.message);
}

const action = payload.actions?.[0];
if (!action) {
  throw new Error('Missing Slack action');
}

const actionValue = action.value || '{}';
let parsedValue = {};

if (typeof actionValue === 'string' && actionValue.startsWith('{')) {
  try {
    parsedValue = JSON.parse(actionValue);
  } catch (e) {
    console.warn('Could not parse action value as JSON:', actionValue);
  }
}

return [{
  json: {
    action_id: action.action_id,
    decision: action.action_id === 'commit_approve' ? 'ok' : 'cancel',
    response_url: payload.response_url || '',
    channel: parsedValue.channel || payload.channel?.id || payload.container?.channel_id || '',
    thread_ts: parsedValue.thread_ts || payload.container?.thread_ts || payload.container?.message_ts || '',
    device: parsedValue.device || 'unknown',
    vendor: parsedValue.vendor || 'unknown',
    commit_payload: parsedValue.commit_payload || ''
  }
}];

// Get input safely
const input = items[0].json;

// If input itself is a string, parse it
const parsed = typeof input === 'string' ? JSON.parse(input) : input;

// Normalize structure (array vs object)
const obj = Array.isArray(parsed) ? parsed[0] : parsed;

// Validate existence
if (!obj || !obj.output) {
  throw new Error('Invalid input format: "output" field not found');
}

// Extract raw string
const rawOutput = obj.output;

// Remove markdown fences
const cleaned = rawOutput
  .replace(/^```json\s*/, '')
  .replace(/```$/, '')
  .trim();

// Parse inner JSON
const finalJson = JSON.parse(cleaned);

// Return
return [
  {
    json: finalJson
  }
];

